mapper.select:
SELECT * FROM chemical_stock
WHERE chemical_type = #{chemicalType}
ORDER BY create_time DESC

SELECT * FROM chemical_stock
WHERE status = #{status}
ORDER BY create_time DESC

mapper.update:
UPDATE chemical_stock
SET available_quantity = available_quantity - #{lockQuantity},
    locked_quantity = locked_quantity + #{lockQuantity},
    update_time = NOW()
WHERE id = #{id}
  AND available_quantity >= #{lockQuantity}

UPDATE chemical_stock
SET available_quantity = available_quantity + #{unlockQuantity},
    locked_quantity = locked_quantity - #{unlockQuantity},
    update_time = NOW()
WHERE id = #{id}
  AND locked_quantity >= #{unlockQuantity}

UPDATE chemical_stock
SET total_quantity = total_quantity - #{outQuantity},
    locked_quantity = locked_quantity - #{outQuantity},
    update_time = NOW()
WHERE id = #{id}
  AND locked_quantity >= #{outQuantity}
